#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int maxGCD(char *s, int n, int m, int x, int y) {
    int maxGcd = 0;
    for (int i = 1; i <= y; i++) {
        int *nums = (int *)malloc((i + 1) * sizeof(int));
        int *separators = (int *)malloc((i) * sizeof(int));
        for (int j = 0; j < i; j++) {
            separators[j] = 0;
        }
        for (int j = 0; j <= i; j++) {
            nums[j] = 0;
        }
        int idx = 0;
        for (int j = 0; j < n; j++) {
            if (idx < i && separators[idx] == 0) {
                separators[idx] = 1;
                idx++;
            }
            nums[idx] = nums[idx] * 10 + (s[j] - '0');
        }
        int currentGcd = nums[0];
        for (int j = 1; j <= i; j++) {
            currentGcd = gcd(currentGcd, nums[j]);
        }
        maxGcd = (currentGcd > maxGcd) ? currentGcd : maxGcd;
        free(nums);
        free(separators);
    }
    return maxGcd;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char *s = (char *)malloc((n + 1) * sizeof(char));
        scanf("%s", s);
        int m, x, y;
        scanf("%d %d %d", &m, &x, &y);
        printf("%d\n", maxGCD(s, n, m, x, y));
        free(s);
    }
    return 0;
}

